def p(g):
    n = len(g)
    red = [(r, c) for r in range(n) for c in range(n) if g[r][c] == 2]
    if not red:
        return [r[:] for r in g]
    min_r = min(r for r, c in red)
    min_c = min(c for r, c in red)
    offs = [(r - min_r, c - min_c) for r, c in red]
    max_dr = max(dr for dr, dc in offs)
    max_dc = max(dc for dr, dc in offs)
    out = [r[:] for r in g]
    for i in range(n - max_dr):
        for j in range(n - max_dc):
            if all(g[i + dr][j + dc] != 5 for dr, dc in offs):
                for dr, dc in offs:
                    out[i + dr][j + dc] = 2
    return out

